        must_clauses = []
        filter_clauses = []

        if query:
            sanitized_query = InputSanitizer.sanitize_query_string(query)
            must_clauses.append({
                'multi_match': {
                    'query': sanitized_query,
                    'fields': ['message', 'log.message', 'error.message'],
                }
            })

        if level:
            filter_clauses.append({'term': {'log.level': level.upper()}})

        if service:
            filter_clauses.append({'term': {'service.name': service}})

        if start_time or end_time:
            range_filter = {}
            if start_time:
                range_filter['gte'] = start_time
            if end_time:
                range_filter['lte'] = end_time
            filter_clauses.append({'range': {'@timestamp': range_filter}})

        body = {
            'query': {
                'bool': {
                    'must': must_clauses if must_clauses else [{'match_all': {}}],
                    'filter': filter_clauses,
                }
            },
            'size': min(max(1, size), 10000),
            'sort': [{'@timestamp': {'order': 'desc'}}],
        }

