    def scroll_search(self, index_name: str, query: dict,
                      scroll: str = '5m', size: int = 1000):
        """Generator for scrolling through large result sets."""
        index_name = InputSanitizer.sanitize_index_name(index_name)

        try:
            response = self.es.search(
                index=index_name,
                body=query,
                scroll=scroll,
                size=size,
            )

            scroll_id = response.get('_scroll_id')
            hits = response['hits']['hits']

            while hits:
                for hit in hits:
                    yield {
                        'id': hit['_id'],
                        'index': hit['_index'],
                        'source': hit['_source'],
                        'score': hit.get('_score'),
                    }

                response = self.es.scroll(scroll_id=scroll_id, scroll=scroll)
                scroll_id = response.get('_scroll_id')
                hits = response['hits']['hits']

            # Clean up scroll context
            if scroll_id:
                self.es.clear_scroll(scroll_id=scroll_id)

        except es_exceptions.RequestError as e:
            logger.error("Scroll search failed: %s", str(e))
            raise

    @staticmethod
    def _format_search_results(response: dict) -> dict:
        """Format Elasticsearch response into a cleaner structure."""
        hits = response.get('hits', {})
        total = hits.get('total', {})
        if isinstance(total, dict):
            total_count = total.get('value', 0)
        else:
            total_count = total

        results = {
            'total': total_count,
            'max_score': hits.get('max_score'),
            'took_ms': response.get('took', 0),
            'hits': [],
        }

        for hit in hits.get('hits', []):
            result = {
                'id': hit['_id'],
                'index': hit['_index'],
                'score': hit.get('_score'),
                'source': hit.get('_source', {}),
            }
            if 'highlight' in hit:
                result['highlight'] = hit['highlight']
            results['hits'].append(result)

        return results


